import java.util.*;

public int maxStarSum(int[] vals, int[][] edges, int k) {
    List<Integer>[] adj = new ArrayList[vals.length];
    for (int i = 0; i < vals.length; i++) {
        adj[i] = new ArrayList<Integer>();
    }

    for (int[] edge : edges) {
        adj[edge[0]].add(vals[edge[1]]);
        adj[edge[1]].add(vals[edge[0]]);
    }

    int ans = Integer.MIN_VALUE;
    for (int i = 0; i < vals.length; i++) {
        Collections.sort(adj[i], Collections.reverseOrder());
        int sum = vals[i];
        for (int j = 0; j < k && j < adj[i].size(); j++) {
            sum += adj[i].get(j);
        }
        ans = Math.max(ans, sum);
    }

    return ans;
}
```

